// src/components/Header.js
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

// Exemplo de ícone de avatar (pode trocar por imagem sua)
// Vou usar um SVG simples de “usuário” (pode ficar em linha ou importar de outro lugar):
const AvatarIcon = () => (
<svg xmlns="http://www.w3.org/2000/svg" id="avatar-man-profile-person-human-boy" width="42" height="42" viewBox="0 0 16 16">
  <g transform="translate(0 -1036.362)">
    <circle cx="8" cy="1044.362" r="8" fill="#1d67b1"></circle>
    <path fill="#2a2f3c" d="M5.978 1046.475H10v.965H5.978z"></path>
    <path fill="#272a4d" d="M7.186 1039.854h1.81c.823 0 1.486.74 1.486 1.658 0 .918-.663 1.657-1.486 1.657h-1.81c-.824 0-1.487-.74-1.487-1.657 0-.918.663-1.657 1.487-1.657z"></path>
    <rect width="5.294" height="3.455" x="5.189" y="1040.835" fill="#272a4d" rx=".903" ry=".903"></rect>
    <path fill="#272a4d" d="M8.005 1039.854H9.42c.684 0 1.062-.8 1.062-.36v3.468c0 .193-.13.348-.293.348H8.005c-.163 0-.294-.155-.294-.348v-2.76c0-.193.131-.347.294-.347z"></path>
    <path fill="#ffce77" d="M8.832 1041.702c-.866-.021-2.275.08-2.275.08 0 .6-.792.95-.807 1.56v1.145c.057.81.278 1.378.713 1.727-.05.402-.224.634-.512.847-.34.253-.838.449-1.361.672-.523.223-1.079.492-1.506.965-.316.35-.547.804-.647 1.402A8 8 0 0 0 8 1052.362a8 8 0 0 0 5.555-2.244c-.1-.588-.333-1.036-.647-1.375-.424-.458-.973-.704-1.49-.922-.517-.218-1.01-.412-1.346-.672-.33-.255-.518-.548-.525-1.111.454-.376.67-.905.69-1.551v-1.486c0-.817-.62-1.3-1.405-1.3z"></path>
    <path fill="#ff2a7f" d="m9.758 1046.735-1.754 2.29-1.754-2.257a1.395 1.395 0 0 1-.28.283c-.34.254-.845.444-1.368.668-.524.225-1.083.512-1.51.987-.318.353-.55.8-.649 1.4A8 8 0 0 0 8 1052.362a8 8 0 0 0 5.56-2.25c-.1-.586-.33-1.032-.644-1.371-.424-.46-.958-.697-1.475-.916-.516-.22-.998-.443-1.334-.703a1.275 1.275 0 0 1-.35-.387z"></path>
    <path fill="#323b52" d="m6.054 1046.52 1.24 1.606-.662.55c-.221.222-.353.035-.412-.068l-.77-1.254.429-.802c.066-.116.133-.074.174-.032zm3.865 0-1.24 1.606.662.55c.221.222.353.035.412-.068l.77-1.254-.429-.802c-.066-.116-.132-.074-.174-.032z"></path>
  </g>
</svg>
);

export default function Header() {
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  // Alterna visibilidade do dropdown
  const toggleDropdown = () => {
    setDropdownOpen(prev => !prev);
  };

  // Função para ir ao perfil do aluno logado
  const handlePerfil = () => {
    setDropdownOpen(false);
    // Se você tiver uma rota dedicada para editar perfil, por exemplo "/perfil",
    // basta navegar para ela. Se quiser usar a tela de FormAluno passando
    // o próprio ID, seria algo como: navigate(`/alunos/${user.id}/editar`).
    navigate('/perfil');
  };

  // Função para sair
  const handleLogout = () => {
    setDropdownOpen(false);
    logout();
    navigate('/login', { replace: true });
  };

  // Opicional: fechar o dropdown se clicar fora (bastante útil)
  // Podemos adicionar um listener no document, mas para manter simples:
  // se o usuário clicar em qualquer outra parte da página (exceto no 
  // próprio dropdown), podemos forçar fechar. Isso requer um pouco mais de
  // código, mas não é obrigatório — deixarei de fora para simplificar.

  return (
    <header className="fixed top-0 left-0 right-0 h-16 bg-white shadow flex items-center justify-between px-6 z-50">
      {/* LOGO ou título */}
      <div className="flex items-center">
        <h1 className="text-xl font-bold text-[#3172C0]">PoliUB Atendimentos</h1>
      </div>

      {/* Área do avatar e dropdown */}
      <div className="relative">
        {/* Botão do Avatar */}
        <button
          onClick={toggleDropdown}
          className="rounded-full focus:outline-none focus:ring-2 focus:ring-blue-400"
        >
          <AvatarIcon />
        </button>

        {/* Dropdown */}
        {dropdownOpen && (
          <ul className="absolute right-0 mt-2 w-48 bg-white border border-gray-200 rounded-lg shadow-lg">
            {/* Exibir o nome do usuário logado */}
            <li className="px-4 py-2 text-gray-700 font-medium border-b border-gray-100">
              {user?.usuario || 'Usuário'}
            </li>

            {/* Opção “Meu Perfil” */}
            <li>
              <button
                onClick={handlePerfil}
                className="w-full text-left px-4 py-2 hover:bg-gray-100 text-gray-700"
              >
                Meu Perfil
              </button>
            </li>

            {/* Espaço opcional para inserir outras opções, ex: Configurações */}
            {/* Exemplo:
            <li>
              <button
                onClick={() => { /* alguma ação *\/ }}
                className="w-full text-left px-4 py-2 hover:bg-gray-100 text-gray-700"
              >
                Configurações
              </button>
            </li>
            */}

            {/* Opção “Sair” */}
            <li>
              <button
                onClick={handleLogout}
                className="w-full text-left px-4 py-2 hover:bg-gray-100 text-red-600"
              >
                Sair
              </button>
            </li>
          </ul>
        )}
      </div>
    </header>
  );
}
